'use client';

import React from 'react';
import { Search, Plus, Bell, Settings2 } from 'lucide-react';

const Topbar = () => {
    return (
        <header className="h-[80px] bg-white/80 backdrop-blur-md border-b border-gray-100 px-8 flex items-center justify-between sticky top-0 z-30 transition-all">
            {/* Search Section */}
            <div className="flex-1 max-w-xl">
                <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-teal-600 transition-colors" size={18} />
                    <input
                        type="text"
                        placeholder="Search patients, nurses, bookings..."
                        className="w-full bg-gray-50 border border-gray-100 rounded-xl py-2.5 pl-12 pr-4 text-[14px] text-gray-600 focus:outline-none focus:ring-4 focus:ring-teal-500/5 focus:border-teal-500/50 transition-all outline-none"
                    />
                </div>
            </div>

            {/* Actions Section */}
            <div className="flex items-center gap-6">
                <button className="flex items-center gap-2 bg-[#0D9488] hover:bg-[#0B7A6F] text-white px-5 py-2.5 rounded-xl text-[14px] font-bold transition-all shadow-lg shadow-teal-500/10 active:scale-95">
                    <Plus size={18} strokeWidth={3} />
                    <span>New Booking</span>
                </button>

                <div className="flex items-center gap-1.5 border-l border-gray-100 pl-6">
                    <button className="w-11 h-11 flex items-center justify-center text-gray-400 hover:text-gray-600 hover:bg-gray-50 rounded-xl transition-all relative">
                        <Bell size={20} />
                        <span className="absolute top-[10px] right-[10px] w-2 h-2 bg-red-500 rounded-full border-2 border-white shadow-sm shadow-red-500/20 animate-pulse"></span>
                    </button>

                    <button className="w-11 h-11 flex items-center justify-center text-gray-400 hover:text-gray-600 hover:bg-gray-50 rounded-xl transition-all">
                        <Settings2 size={20} />
                    </button>

                    <div className="ml-3 w-11 h-11 bg-[#0D9488] rounded-full flex items-center justify-center text-white text-[13px] font-bold shadow-md shadow-teal-500/10 border border-white">
                        AS
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Topbar;
