'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
    LayoutDashboard,
    FileText,
    Users,
    UserRound,
    UserPlus,
    ClipboardList,
    Calendar,
    CreditCard,
    BarChart2,
    Settings,
    ChevronRight,
    LogOut
} from 'lucide-react';

const sidebarItems = [
    { name: 'Dashboard', icon: LayoutDashboard, href: '/admin' },
    { name: 'Bookings', icon: FileText, href: '/admin/bookings', hasChevron: true },
    { name: 'Patients', icon: Users, href: '/admin/patients' },
    { name: 'Nurses', icon: UserRound, href: '/admin/nurses' },
    { name: 'Applications', icon: UserPlus, href: '/admin/applications' },
    { name: 'Assignments', icon: ClipboardList, href: '/admin/assignments' },
    { name: 'Schedule', icon: Calendar, href: '/admin/schedule' },
    { name: 'Payments', icon: CreditCard, href: '/admin/payments' },
    { name: 'Reports', icon: BarChart2, href: '/admin/reports' },
    { name: 'Settings', icon: Settings, href: '/admin/settings' },
];

const Sidebar = () => {
    const pathname = usePathname();

    return (
        <aside className="w-64 bg-white border-r border-gray-100 flex flex-col h-screen fixed left-0 top-0 z-40">
            {/* Logo Section */}
            <div className="p-6 flex items-center gap-3 border-b border-gray-50">
                <div className="w-10 h-10 bg-white flex items-center justify-center">
                    <img src="/logo.png" alt="Life Comrades" className="w-full h-full object-contain" />
                </div>
                <div>
                    <h1 className="text-gray-900 font-bold text-[15px] leading-tight">Life Comrades</h1>
                    <p className="text-gray-400 text-[11px]">Chennai Nursing</p>
                </div>
            </div>

            {/* Navigation Links */}
            <nav className="flex-1 px-3 mt-4 overflow-y-auto">
                <ul className="space-y-1">
                    {sidebarItems.map((item) => {
                        const isActive = pathname === item.href || (item.href === '/admin' && pathname === '/admin');
                        const isBookings = item.name === 'Bookings' && pathname.startsWith('/admin/bookings');
                        const highlight = isActive || isBookings;

                        return (
                            <li key={item.name}>
                                <Link
                                    href={item.href}
                                    className={`flex items-center justify-between px-4 py-2.5 rounded-xl text-[14px] transition-all duration-200 ${highlight
                                        ? 'bg-teal-50 text-teal-600 font-semibold shadow-sm shadow-teal-500/5'
                                        : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'
                                        }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <item.icon size={18} strokeWidth={highlight ? 2 : 1.5} />
                                        <span>{item.name}</span>
                                    </div>
                                    {item.name === 'Bookings' && (
                                        <ChevronRight size={14} className={`transition-transform ${isBookings || isActive ? 'rotate-90' : ''}`} />
                                    )}
                                </Link>
                                {item.name === 'Bookings' && highlight && (
                                    <ul className="mt-1 ml-10 space-y-1">
                                        <li>
                                            <Link href="/admin/bookings" className={`block py-2 text-[13px] ${pathname === '/admin/bookings' ? 'text-teal-600 font-semibold' : 'text-gray-400 hover:text-gray-600'}`}>
                                                All Bookings
                                            </Link>
                                        </li>
                                        {['New Requests', 'Assigned', 'In Progress', 'Completed', 'Cancelled'].map(sub => (
                                            <li key={sub}>
                                                <Link href="#" className="block py-2 text-[13px] text-gray-400 hover:text-teal-600 transition-colors uppercase tracking-tight">{sub}</Link>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </li>
                        );
                    })}
                </ul>
            </nav>

            {/* Admin Profile */}
            <div className="p-4 border-t border-gray-100 mt-auto bg-gray-50/30">
                <div className="flex items-center gap-3 px-2 py-2 mb-2">
                    <div className="w-10 h-10 bg-teal-600 rounded-full flex items-center justify-center text-white text-[13px] font-bold shadow-lg shadow-teal-500/20 border-2 border-white">
                        AS
                    </div>
                    <div className="flex-1 min-w-0">
                        <h4 className="text-sm font-semibold text-gray-900 truncate">Admin User</h4>
                        <p className="text-[11px] text-gray-400 truncate">admin@carehome.in</p>
                    </div>
                </div>
                <button className="flex items-center gap-2 w-full px-2 py-2 text-gray-500 hover:text-red-500 transition-colors text-sm font-medium">
                    <LogOut size={16} />
                    <span>Logout</span>
                </button>
            </div>
        </aside>
    );
};

export default Sidebar;
